package concrete.goonie.chart.api.data.render; import concrete.goonie.chart.api.data.RectDataSet; import concrete.goonie.chart.internal.render.*; public final class RectDataSetRenderer { public void render(RectDataSet d, RenderList out, Transform t, int visibleFrom, int visibleTo){ for(int i = 0; i<d.sizeValue(); i++){ double x1=d.xValue(i), x2=d.x2Value(i); if(x2<visibleFrom || x1>visibleTo) continue; float left=t.worldToScreenX(Math.min(x1,x2)), right=t.worldToScreenX(Math.max(x1,x2)), top=t.worldToScreenY(Math.max(d.yValue(i),d.y2Value(i))), bottom=t.worldToScreenY(Math.min(d.yValue(i),d.y2Value(i))); out.add(new RenderCommand.RoundedRect(left,top,right,bottom,d.getRectStyle().cornerRadius>0?d.getRectStyle().cornerRadius:8f,d.getRectStyle())); out.add(new RenderCommand.RoundedRect(left,top,right,bottom,d.getBorderStyle().cornerRadius>0?d.getBorderStyle().cornerRadius:8f,d.getBorderStyle())); String label=d.label(i); if(label!=null && !label.isBlank()) out.add(new RenderCommand.Text(left+6f, top+14f, label, 11f, new Style(0xFFE5E7EB,1f,false))); } } }